SELECT CAST(COUNT(CASE WHEN SEX = 'F' AND year(Birthday) > '1930' THEN ID END) AS REAL) * 100 / COUNT(CASE WHEN SEX = 'F' THEN ID END) AS Percentage
FROM Patient
WHERE SEX = 'F' AND year(Birthday) > '1930';

141:
SELECT CAST(COUNT(CASE WHEN T1.height < 180 AND T2.overall_rating > 70 THEN T1.id ELSE NULL END) AS REAL) * 100 / COUNT(T1.id) AS percentage
FROM Player AS T1
JOIN Player_Attributes AS T2 ON T1.player_api_id = T2.player_api_id;
